      "搜索科→验证组": {
        "输入格式": "JSON数组，包含{url, title, snippet, source_type, date}",
        "交付条件": "至少2个独立来源提及CFO姓名",
        "触发条件": "搜索科完成检索后立即交付"
      },
      "验证组→数据组": {
        "输入格式": "JSON对象，包含{cfo_name, effective_date, source_url, verification_status}",
        "交付条件": "来源权威性评级≥B级(官方/权威媒体)",
        "异常处理": "来源冲突时提交所有候选供裁决"
      }
    },
    "milestones": {
      "M1-搜索完成": {
        "截止时间": "T+5min",
        "验收标准": "获得≥3条提及Airbnb CFO的搜索结果，覆盖2025年时效性",
        "检查动作": "核对搜索结果的日期字段与来源多样性"
      },
      "M2-验证完成": {
        "截止时间": "T+8min",
        "验收标准": "确认单一CFO姓名，至少1个A级来源(官方/SEC)或2个B级来源(权威媒体)交叉验证",
        "检查动作": "fetch页面内容核验姓名准确性"
      },
      "M3-最终交付": {
        "截止时间": "T+10min",
        "验收标准": "输出符合格式要求的CFO身份信息",
        "检查动作": "核对答案完整性与来源可追溯性"
      }
    }
  }
}
